const rawOutput = $input.first().json.output;

// Clean markdown wrappers
let cleaned = rawOutput.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim();

// Extract only the JSON object
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1) cleaned = cleaned.slice(start, end + 1);

// Fix unescaped newlines inside JSON strings (character by character)
let inString = false, escaped = false, result = '';
for (let i = 0; i < cleaned.length; i++) {
  const ch = cleaned[i];
  if (escaped) { result += ch; escaped = false; continue; }
  if (ch === '\\') { result += ch; escaped = true; continue; }
  if (ch === '"') { inString = !inString; result += ch; continue; }
  if (inString && ch === '\n') { result += '\\n'; continue; }
  if (inString && ch === '\r') { continue; }
  if (inString && ch === '\t') { result += '\\t'; continue; }
  result += ch;
}

let parsed;
try {
  parsed = JSON.parse(result);
} catch(e) {
  parsed = {
    classification: 'INFORMATIONAL', reason: 'Parse fallback',
    key_ask: null, escalation_needed: false,
    escalate_to_name: null, escalate_to_email: null,
    escalation_reason: null, note_to_colleague: null,
    draft_reply: 'Thank you for your email. I will review and respond shortly.\n\nBest regards,\n[YOUR NAME]\nAI & Digital Health Specialist | [Your Organization]'
  };
}

// Restore real line breaks in email body
if (parsed.draft_reply) {
  parsed.draft_reply = parsed.draft_reply.replace(/\\n/g, '\n');
}

// ── Grab From/Subject/ThreadId from whichever trigger fired ──
const normalizeNode = $('Normalize Email Input').isExecuted
  ? $('Normalize Email Input').first()?.json
  : null;

const gmailNode = (() => {
  try { return $('Gmail Trigger').first()?.json; } catch(e) { return null; }
})();

const fromField    = normalizeNode?.['From']    || gmailNode?.['From']    || '';
const subjectField = normalizeNode?.['Subject'] || gmailNode?.['Subject'] || '';
const threadField = normalizeNode?.threadId || gmailNode?.threadId || '';

// Extract sender first name
let firstName = 'there';
const displayMatch = fromField.match(/^"?([A-Za-z][^"<@]+?)"?\s*</);
if (displayMatch) {
  firstName = displayMatch[1].trim().split(/\s+/)[0];
  firstName = firstName.charAt(0).toUpperCase() + firstName.slice(1).toLowerCase();
} else {
  const prefix = fromField.split('@')[0].replace(/[^a-zA-Z]/g, '');
  if (prefix) firstName = prefix.charAt(0).toUpperCase() + prefix.slice(1);
}

// Fix any bad greeting patterns
if (parsed.draft_reply) {
  parsed.draft_reply = parsed.draft_reply
    .replace(/Dear\s*,/gi, `Dear ${firstName},`)
    .replace(/Dear \[Sender\]/gi, `Dear ${firstName}`)
    .replace(/Dear [Tt]here/gi, `Dear ${firstName}`)
    .replace(/Hi\s*,/gi, `Hi ${firstName},`)
    .replace(/Hi \[Sender\]/gi, `Hi ${firstName}`);
}

return [{ json: {
  ...parsed,
  sender_name: firstName,
  gmail_from: fromField,
  gmail_subject: subjectField,
  gmail_thread_id: threadField
}}];

