  json: {
    Subject: body.Subject || body.subject || "Q1 Programme Update Request",
    From: body.From || body.from || "Sarah Johnson <sarah.johnson@example.org>",
    snippet: body.snippet || body.body || body.email_body || "",
    text: body.text || body.body || body.email_body || "",
    threadId: body.threadId || "demo-thread-001"
  }
}];

// Gmail Trigger data was lost — restore it explicitly
const emailData = $('Gmail Trigger').first().json;
const rosterData = $('Roster').first().json;  // for lookup only

return [{
  json: {
    ...emailData,  // Subject, From, Body, threadId
